import React, { useState } from "react";
import axios from "axios";
import toast from "react-hot-toast";

export default function Chatbot() {
  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([]);
  const token = localStorage.getItem("token");

  const sendMessage = async () => {
    if (!message) return;
    setChat([...chat, { sender: "user", text: message }]);
    setMessage("");

    try {
      const res = await axios.post(
        "http://localhost:5000/api/chatbot",
        { message },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setChat((prev) => [...prev, { sender: "bot", text: res.data.reply }]);
    } catch (err) {
      toast.error("Sorry, AI server is not responding.");
      setChat((prev) => [...prev, { sender: "bot", text: "AI server error" }]);
    }
  };

  return (
    <div className="w-80 bg-white border shadow-lg rounded-lg p-3 fixed bottom-5 right-5 z-50">
      <div className="h-60 overflow-y-auto mb-2">
        {chat.map((c, idx) => (
          <div
            key={idx}
            className={`p-1 my-1 rounded ${
              c.sender === "user"
                ? "text-right bg-blue-100"
                : "text-left bg-gray-100"
            }`}
          >
            {c.text}
          </div>
        ))}
      </div>
      <div className="flex gap-1">
        <input
          type="text"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          placeholder="Type your message..."
          className="flex-1 border p-1 rounded"
        />
        <button
          onClick={sendMessage}
          className="bg-blue-600 text-white px-3 rounded hover:bg-blue-700"
        >
          Send
        </button>
      </div>
    </div>
  );
}
